sql:
SELECT wetland_name, size_acres
FROM wetlands
WHERE size_acres > 100;

external_knowledge:
- "Busy beacons" refers to active stations with more than 5 events in a year; 
- "Protected havens" refers to protected wetlands; 
- "Disturbed" refers to the occurrence of an event.

sql:
SELECT COUNT(*) AS total_measurements
FROM depth_measurements
WHERE station_id = 1;

SELECT station_id, COUNT(*) AS total_measurements
FROM depth_measurements
GROUP BY station_id;

SELECT wetland_name
FROM wetlands
ORDER BY wetland_name ASC;
